mapper.select:
select a.*, t.tag_name
from article a
left join tag t
on a.tag_id = t.tag_id


        a.title like concat('%',#{query},'%')


        and a.article_id = #{articleId}


        and a.user_id = #{userId}


        and t.tag_name = #{tag}


        and a.status = #{status}


        and a.is_deleted = #{isDeleted}


        and DATE(a.updated_at) between #{begin} and #{end}


order by a.updated_at desc
